import { IPolicyRepository } from './policy.repository';
import { LeavePolicy } from './policy.model';

export interface ValidationResult {
  valid: boolean;
  errors: string[];
}

export interface IPolicyService {
  getPolicy(leaveTypeId: string): Promise<LeavePolicy>;
  validateRequest(policy: LeavePolicy, startDate: Date, endDate: Date, daysRequested: number): ValidationResult;
}

export class PolicyService implements IPolicyService {
  constructor(private readonly policyRepository: IPolicyRepository) {}

  async getPolicy(leaveTypeId: string): Promise<LeavePolicy> {
    const policy = await this.policyRepository.findByLeaveTypeId(leaveTypeId);
    if (!policy) {
      throw new Error(`Policy not found for leave type ID: ${leaveTypeId}`);
    }
    if (policy.status !== 'active') {
      throw new Error(`Policy for leave type ID ${leaveTypeId} is not active`);
    }
    return policy;
  }

  validateRequest(policy: LeavePolicy, startDate: Date, endDate: Date, daysRequested: number): ValidationResult {
    const errors: string[] = [];
    // Check max consecutive days
    const diffTime = endDate.getTime() - startDate.getTime();
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1; // inclusive
    if (diffDays > policy.max_consecutive_days) {
      errors.push(`Requested ${diffDays} consecutive days exceeds maximum allowed ${policy.max_consecutive_days}`);
    }
    // Check blackout dates
    if (policy.blackout_dates && policy.blackout_dates.length > 0) {
      const requestDates = this.getDateRange(startDate, endDate);
      const blackoutSet = new Set(policy.blackout_dates.map(d => d.toISOString().split('T')[0]));
      const conflictingDates = requestDates.filter(d => blackoutSet.has(d));
      if (conflictingDates.length > 0) {
        errors.push(`Request includes blackout dates: ${conflictingDates.join(', ')}`);
      }
    }
    return { valid: errors.length === 0, errors };
  }

  private getDateRange(start: Date, end: Date): string[] {
    const dates: string[] = [];
    const current = new Date(start);
    while (current <= end) {
      dates.push(current.toISOString().split('T')[0]);
      current.setDate(current.getDate() + 1);
    }
    return dates;
  }
}
